// Readwise Reader API - Programmatic Content Capture
// Requires a Readwise API token from Settings → API

const READWISE_API_TOKEN = 'your-api-token-here';
const READWISE_API_BASE = 'https://readwise.io/api/v2';

// Function to save a URL to Reader
async function saveURLToReader(url, title = null, tags = []) {
  const response = await fetch(`${READWISE_API_BASE}/save/`, {
    method: 'POST',
    headers: {
      'Authorization': `Token ${READWISE_API_TOKEN}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      url: url,
      title: title,
      tags: tags,
      saved_using: 'api-custom-script'
    })
  });

  if (!response.ok) {
    throw new Error(`API Error: ${response.status}`);
  }

  return await response.json();
}

// Example usage
(async () => {
  try {
    const result = await saveURLToReader(
      'https://example.com/interesting-article',
      'Custom Article Title',
      ['web-clip', 'api-test']
    );
    console.log('Successfully saved:', result);
  } catch (error) {
    console.error('Failed to save:', error.message);
  }
})();

{
  "description": "Gmail filter rules for Readwise Reader email forwarding",
  "filters": [
    {
      "name": "Newsletter Filter",
      "criteria": {
        "from": "*@newsletter.*",
        "subject": "[Newsletter]"
      },
      "actions": {
        "forward": "yourname@reader.readwise.io",
        "add_label": "Newsletter/Forwarded",
        "mark_as_read": true,
        "skip_inbox": false
      }
    },
    {
      "name": "Tech Digest Filter",
      "criteria": {
        "to": "reader-tech@yourdomain.com"
      },
      "actions": {
        "forward": "yourname@reader.readwise.io",
        "add_label": "Tech/Reader",
        "mark_as_read": true
      }
    },
    {
      "name": "Manual Forward Trigger",
      "criteria": {
        "subject": "FWD:*",
        "has_the_word": "[[save-to-reader]]"
      },
      "actions": {
        "forward": "yourname@reader.readwise.io",
        "mark_as_read": true
      }
    }
  ]
}

