def opml_to_json(opml_file):
    tree = ET.parse(opml_file)
    root = tree.getroot()

    feeds = []
    categories = {}

    for outline in root.iter('outline'):
        xml_url = outline.get('xmlUrl')
        if xml_url:
            feed = {
                'title': outline.get('text', 'Untitled'),
                'xmlUrl': xml_url,
                'htmlUrl': outline.get('htmlUrl', ''),
                'category': outline.get('category', 'Uncategorized')
            }
            feeds.append(feed)

            if feed['category'] not in categories:
                categories[feed['category']] = []
            categories[feed['category']].append(feed['title'])

    result = {
        'total_feeds': len(feeds),
        'feeds': feeds,
        'categories': categories
    }

    return result

