```python
import requests
import json
from datetime import datetime

class SnipdReadwiseSync:
    def __init__(self, snipd_token, readwise_token):
        self.snipd_token = snipd_token
        self.readwise_token = readwise_token
        self.snipd_api = 'https://api.snipd.com'
        self.readwise_api = 'https://readwise.io/api/v2'

    def get_snipd_highlights(self, limit=50):
        """Fetch recent highlights from Snipd"""
        headers = {'Authorization': f'Bearer {self.snipd_token}'}
        response = requests.get(
            f'{self.snipd_api}/highlights',
            headers=headers,
            params={'limit': limit}
        )
        return response.json()

    def format_for_readwise(self, snipd_highlight):
        """Convert Snipd highlight format to Readwise format"""
        return {
            'url': snipd_highlight['episode_url'],
            'title': snipd_highlight['episode_title'],
            'category': 'podcast',
            'highlights': [{
                'text': snipd_highlight['text'],
                'timestamp': snipd_highlight['timestamp'],
                'note': snipd_highlight.get('user_note', ''),
                'location': snipd_highlight.get('position', 0)
            }],
            'saved_at': snipd_highlight['created_at'],
            'tags': ['snipd', 'podcast', 'synced']
        }

    def sync_to_readwise(self):
        """Sync all Snipd highlights to Readwise"""
        snipd_highlights = self.get_snipd_highlights()

        for highlight in snipd_highlights:
            readwise_format = self.format_for_readwise(highlight)

            response = requests.post(
                f'{self.readwise_api}/highlights/',
                headers={
                    'Authorization': f'Token {self.readwise_token}',
                    'Content-Type': 'application/json'
                },
                json=readwise_format
            )

            if response.status_code == 201:
                print(f"Synced: {highlight['episode_title'][:50]}")
            elif response.status_code == 400:
                print(f"Already exists: {highlight['id']}")

# Usage
syncer = SnipdReadwiseSync(
    snipd_token='your-snipd-token',
    readwise_token='your-readwise-token'
)
syncer.sync_to_readwise()
```



## Common Mistakes

- Creating overly long video highlights that cover multiple topics, reducing review effectiveness and making the segment difficult to rewatch
- Forgetting to add personal notes to video highlights, leaving only the transcript text without context about why the moment matters
- Relying solely on automatic captions without verifying accuracy, leading to incorrect or nonsensical highlights when reviewed
- Saving too many videos without proper organization, creating a cluttered library where important highlights become buried
- Skipping the transcript when available and using rough timestamp estimates instead, resulting in imprecise highlight boundaries
- Not establishing a consistent tagging system for multimedia content, making it difficult to filter and review related material
- Saving videos without watching them first, resulting in low-quality or irrelevant content in your library
- Creating highlights without setting up proper review schedules, missing the spaced repetition benefits for retention


## Best Practices

- Keep video highlights focused on a single insight or concept, typically spanning 15-60 seconds of content for optimal review
- Always add a personal annotation explaining the significance of the highlight and how it connects to your existing knowledge
- Verify transcript accuracy by watching the highlighted segment before finalizing the highlight
- Create a consistent tagging taxonomy for multimedia content separate from text content, using prefixes like 'video:' or 'podcast:'
- Use video notes for broader observations that don't fit a specific transcript segment but are worth marking
- Organize long videos into logical sections using personal chapter markers for easier navigation during review
- Schedule dedicated review sessions for multimedia content, accounting for the additional time required to watch video segments
- Maintain a capture-first workflow: quickly save videos when you discover them, then process highlights during designated processing time

