// Timestamp utility functions for video highlighting

// Convert seconds to HH:MM:SS format
function secondsToTimestamp(seconds) {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);

    return [hrs, mins, secs]
        .map(unit => unit.toString().padStart(2, '0'))
        .join(':');
}

// Convert HH:MM:SS to seconds
function timestampToSeconds(timestamp) {
    const parts = timestamp.split(':').map(Number);

    if (parts.length === 3) {
        return parts[0] * 3600 + parts[1] * 60 + parts[2];
    } else if (parts.length === 2) {
        return parts[0] * 60 + parts[1];
    }
    return parts[0];
}

// Calculate duration between two timestamps
function calculateDuration(startTimestamp, endTimestamp) {
    const startSeconds = timestampToSeconds(startTimestamp);
    const endSeconds = timestampToSeconds(endTimestamp);
    return endSeconds - startSeconds;
}

// Generate YouTube embed URL with start/end parameters
function generateYouTubeEmbedUrl(videoId, startTimestamp, endTimestamp) {
    const baseUrl = `https://www.youtube.com/embed/${videoId}`;
    const params = new URLSearchParams();

    if (startTimestamp) {
        params.set('start', timestampToSeconds(startTimestamp).toString());
    }
    if (endTimestamp) {
        params.set('end', timestampToSeconds(endTimestamp).toString());
    }

    return `${baseUrl}?${params.toString()}`;
}

