import requests

class ReadwiseReaderAPI:
    def __init__(self, api_token):
        self.api_token = api_token
        self.base_url = "https://readwise.io/api/v2"
        self.headers = {
            "Authorization": f"Token {api_token}",
            "Content-Type": "application/json"
        }

    def get_review_settings(self):
        """Retrieve current review configuration."""
        response = requests.get(
            f"{self.base_url}/review-statistics/",
            headers=self.headers
        )
        return response.json()

    def update_daily_limit(self, daily_limit):
        """Update the maximum highlights reviewed per day."""
        payload = {"daily_review_limit": daily_limit}
        response = requests.post(
            f"{self.base_url}/settings/",
            json=payload,
            headers=self.headers
        )
        return response.json()

    def get_due_reviews(self):
        """Fetch highlights due for review today."""
        response = requests.get(
            f"{self.base_url}/reviews/",
            headers=self.headers,
            params={"after": "2024-01-01"}
        )
        return response.json()

    def mark_review_complete(self, highlight_id, quality):
        """Record a review with quality rating (0-5).

        Quality ratings:
        0 - Complete blackout
        1 - Incorrect, but remembered upon seeing answer
        2 - Incorrect, but answer seemed easy to recall
        3 - Correct with serious difficulty
        4 - Correct with some hesitation
        5 - Perfect response
        """
        payload = {
            "highlight_id": highlight_id,
            "quality": quality
        }
        response = requests.post(
            f"{self.base_url}/reviews/",
            json=payload,
            headers=self.headers
        )
        return response.json()

# Usage example
