def invoke_anki(action, params={}):
    """Send request to AnkiConnect."""
    response = requests.post(
        ANKICONNECT_URL,
        json={"action": action, "version": 6, "params": params}
    )
    return response.json()

def create_anki_deck(deck_name):
    """Create a new deck in Anki."""
    result = invoke_anki("createDeck", {"deck": deck_name})
    return result.get("result")

def add_basic_card(deck_name, front, back, tags=[]):
    """Add a basic front-back flashcard to Anki."""
    note = {
        "deckName": deck_name,
        "modelName": "Basic",
        "fields": {"Front": front, "Back": back},
        "tags": tags
    }
    result = invoke_anki("addNote", {"note": note})
    return result

def export_highlights_to_anki(highlights, deck_name="Readwise Highlights"):
    """Export list of highlight dictionaries to Anki cards.

    Expected highlight format:
    {
        "text": "The highlight text",
        "note": "Your personal note",
        "book_title": "Source book/article",
        "tags": ["important", "concept"]
    }
    """
    # Ensure deck exists
    create_anki_deck(deck_name)

    added_count = 0
    for highlight in highlights:
        front = f"{highlight['text']}\n\n<i>From: {highlight.get('book_title', 'Unknown')}</i>"
        back = highlight.get('note', 'No notes added.')
        tags = highlight.get('tags', [])

        result = add_basic_card(deck_name, front, back, tags)
        if result.get("error") is None:
            added_count += 1

    return {"total": len(highlights), "added": added_count}

# Example usage
