```javascript
/**
 * Readwise Reader Review Dashboard Generator
 * Run with: node review-dashboard.js
 * 
 * Prerequisites:
 * npm install axios figlet
 */

const axios = require('axios');
const figlet = require('figlet');

const API_TOKEN = process.env.READWISE_API_TOKEN || 'your_token_here';
const API_BASE = 'https://readwise.io/api/v2';

const client = axios.create({
  baseURL: API_BASE,
  headers: {
    'Authorization': `Token ${API_TOKEN}`,
    'Content-Type': 'application/json'
  }
});

async function getReviewStats() {
  try {
    // Get today's reviews
    const reviewsRes = await client.get('/reviews/', {
      params: {
        after: new Date().toISOString().split('T')[0]
      }
    });

    const todayReviews = reviewsRes.data.results || [];
    const completedToday = todayReviews.filter(r => r.quality !== undefined).length;

    // Get highlights summary
    const highlightsRes = await client.get('/highlights/');
    const totalHighlights = highlightsRes.data.count || 0;

    // Get review statistics
    const statsRes = await client.get('/review-statistics/');
    const stats = statsRes.data;

    return {
      completedToday,
      totalHighlights,
      dueToday: stats.due_today || 0,
      totalReviewed: stats.total_reviews || 0,
      averageQuality: stats.average_quality || 0,
      streak: stats.streak_days || 0
    };
  } catch (error) {
    console.error('API Error:', error.message);
    return null;
  }
}

function renderDashboard(stats) {
  if (!stats) {
    console.log('\n⚠️  Unable to fetch data. Check your API token.\n');
    return;
  }

  const progress = stats.dueToday > 0 
    ? Math.round((stats.completedToday / stats.dueToday) * 100)
    : 100;

  const progressBar = '█'.repeat(Math.floor(progress / 5)) + 
                      '░'.repeat(20 - Math.floor(progress / 5));

  console.log(
    figlet.textSync('READWISE', { font: 'Small' })
  );
  console.log('     Review Dashboard\n');
  console.log(`┌─────────────────────────────────────┐`);
  console.log(`│  📊 Progress: [${progressBar}] ${progress}%   │`);
  console.log(`│  ✅ Completed Today: ${stats.completedToday.toString().padStart(3)}           │`);
  console.log(`│  ⏳ Due Today: ${stats.dueToday.toString().padStart(3)}                │`);
  console.log(`│  📚 Total Highlights: ${stats.totalHighlights.toString().padStart(4)}         │`);
  console.log(`│  🔥 Streak: ${stats.streak} days                 │`);
  console.log(`│  ⭐ Avg Quality: ${stats.averageQuality.toFixed(2)}               │`);
  console.log(`└─────────────────────────────────────┘\n`);

  if (progress >= 100) {
    console.log('🎉 Daily review complete! Great work!\n');
  } else {
    console.log(`📝 ${stats.dueToday - stats.completedToday} highlights remaining. Keep going!\n`);
  }
}

// Main execution
(async () => {
  const stats = await getReviewStats();
  renderDashboard(stats);
})();
```



## Common Mistakes

- Setting the daily review limit too high initially, causing review fatigue and eventual abandonment of the system
- Skipping reviews for several days and returning to an overwhelming queue that seems impossible to clear
- Not distinguishing between highlights that deserve spaced repetition and those that are better as reference material
- Always rating reviews as 'easy' or 'perfect' without honest assessment, which causes the algorithm to space reviews too far apart
- Overusing the priority feature, causing all highlights to become priority highlights and negating the purpose
- Integrating with external tools without first establishing a consistent review habit in Readwise itself
- Ignoring the queue during busy periods without adjusting settings, leading to guilt and avoidance behavior


## Best Practices

- Start with a conservative daily limit (15-20 highlights) and only increase after maintaining consistent completion for at least two weeks
- Review at the same time each day, preferably during a period when you are alert and can give full attention to the material
- Be honest with your quality ratings; rating something as 'easy' when you struggled leads to reviews spaced too far apart
- Use tags and categories to organize highlights by importance, reserving priority marking only for truly critical information
- Set up the Anki integration early if you prefer Anki's more customizable algorithm, but understand that both systems require consistent engagement
- Regularly audit your queue to remove highlights that no longer provide value, preventing unnecessary clutter
- Schedule weekly or monthly reviews of your settings to ensure they align with your current learning goals and available time

