/**
 * Readwise Reader Review Dashboard Generator
 * Run with: node review-dashboard.js
 * 
 * Prerequisites:
 * npm install axios figlet
 */

const axios = require('axios');
const figlet = require('figlet');

const API_TOKEN = process.env.READWISE_API_TOKEN || 'your_token_here';
const API_BASE = 'https://readwise.io/api/v2';

const client = axios.create({
  baseURL: API_BASE,
  headers: {
    'Authorization': `Token ${API_TOKEN}`,
    'Content-Type': 'application/json'
  }
});

async function getReviewStats() {
  try {
    // Get today's reviews
    const reviewsRes = await client.get('/reviews/', {
      params: {
        after: new Date().toISOString().split('T')[0]
      }
    });

    const todayReviews = reviewsRes.data.results || [];
    const completedToday = todayReviews.filter(r => r.quality !== undefined).length;

    // Get highlights summary
    const highlightsRes = await client.get('/highlights/');
    const totalHighlights = highlightsRes.data.count || 0;

    // Get review statistics
    const statsRes = await client.get('/review-statistics/');
    const stats = statsRes.data;

    return {
      completedToday,
      totalHighlights,
      dueToday: stats.due_today || 0,
      totalReviewed: stats.total_reviews || 0,
      averageQuality: stats.average_quality || 0,
      streak: stats.streak_days || 0
    };
  } catch (error) {
    console.error('API Error:', error.message);
    return null;
  }
}

function renderDashboard(stats) {
  if (!stats) {
    console.log('\n⚠️  Unable to fetch data. Check your API token.\n');
    return;
  }

  const progress = stats.dueToday > 0 
    ? Math.round((stats.completedToday / stats.dueToday) * 100)
    : 100;

  const progressBar = '█'.repeat(Math.floor(progress / 5)) + 
                      '░'.repeat(20 - Math.floor(progress / 5));

  console.log(
    figlet.textSync('READWISE', { font: 'Small' })
  );
  console.log('     Review Dashboard\n');
  console.log(`┌─────────────────────────────────────┐`);
  console.log(`│  📊 Progress: [${progressBar}] ${progress}%   │`);
  console.log(`│  ✅ Completed Today: ${stats.completedToday.toString().padStart(3)}           │`);
  console.log(`│  ⏳ Due Today: ${stats.dueToday.toString().padStart(3)}                │`);
  console.log(`│  📚 Total Highlights: ${stats.totalHighlights.toString().padStart(4)}         │`);
  console.log(`│  🔥 Streak: ${stats.streak} days                 │`);
  console.log(`│  ⭐ Avg Quality: ${stats.averageQuality.toFixed(2)}               │`);
  console.log(`└─────────────────────────────────────┘\n`);

  if (progress >= 100) {
