import os
from datetime import datetime, timedelta
from readwise import ReadwiseClient
from notion import NotionClient

READWISE_TOKEN = os.environ.get('READWISE_TOKEN')
NOTION_TOKEN = os.environ.get('NOTION_TOKEN')
NOTION_DATABASE_ID = os.environ.get('NOTION_DATABASE_ID')

client = ReadwiseClient(token=READWISE_TOKEN)
notion_client = NotionClient(auth=NOTION_TOKEN)

def should_export_document(doc, rules):
    """Evaluate export rules against a document."""
    for rule in rules:
        field = doc.get(rule['field'])
        operator = rule['operator']
        value = rule['value']

        if operator == 'contains':
            if value not in (field or ''):
                return False
        elif operator == 'equals':
