    { field: 'sourceUrl', operator: 'contains', value: 'github.com' }
  ],
  actions: [
    { type: 'apply_tag', config: { tags: ['code', 'technical'] } }
  ],
  enabled: true
});

// Run processing
automation.runScheduledProcessing();
