import os
from datetime import datetime, timedelta
from readwise import ReadwiseClient
from notion import NotionClient

READWISE_TOKEN = os.environ.get('READWISE_TOKEN')
NOTION_TOKEN = os.environ.get('NOTION_TOKEN')
NOTION_DATABASE_ID = os.environ.get('NOTION_DATABASE_ID')

client = ReadwiseClient(token=READWISE_TOKEN)
notion_client = NotionClient(auth=NOTION_TOKEN)

def should_export_document(doc, rules):
    """Evaluate export rules against a document."""
    for rule in rules:
        field = doc.get(rule['field'])
        operator = rule['operator']
        value = rule['value']

        if operator == 'contains':
            if value not in (field or ''):
                return False
        elif operator == 'equals':
            if field != value:
                return False
        elif operator == 'greater_than':
            if not field or field <= value:
                return False
        elif operator == 'regex':
            import re
            if not re.search(value, field or ''):
                return False
    return True

export_rules = [
    {
        'name': 'Export technical content to Notion',
        'conditions': [
            {'field': 'source_url', 'operator': 'contains', 'value': 'github.com'},
            {'field': 'num_highlights', 'operator': 'greater_than', 'value': 3}
        ],
        'action': 'notion_task'
    },
    {
        'name': 'Export research to reference manager',
        'conditions': [
            {'field': 'source_url', 'operator': 'regex', 'value': r'(arxiv\.org|pubmed\.ncbi)'}
        ],
        'action': 'zotero_export'
    },
    {
        'name': 'Weekly newsletter digest',
        'conditions': [
            {'field': 'source_url', 'operator': 'contains', 'value': 'substack.com'},
            {'field': 'saved_at', 'operator': 'greater_than', 'value': (datetime.now() - timedelta(days=7)).isoformat()}
        ],
        'action': 'slack_digest'
    }
]

def process_documents():
    """Main processing loop for conditional exports."""
    documents = client.list_documents(
        updated_after=(datetime.now() - timedelta(hours=24)).isoformat()
    )

    exported_count = 0

    for doc in documents:
        for rule in export_rules:
            if should_export_document(doc, rule['conditions']):
                print(f"Document '{doc['title']}' matches rule: {rule['name']}")

                if rule['action'] == 'notion_task':
                    notion_client.create_page(
                        database_id=NOTION_DATABASE_ID,
                        title=doc['title'],
                        url=doc['source_url'],
                        highlights_count=doc['num_highlights'],
                        tags=doc.get('tags', [])
                    )
                elif rule['action'] == 'zotero_export':
                    # Zotero API integration would go here
                    pass
                elif rule['action'] == 'slack_digest':
                    # Slack webhook integration would go here
                    pass

                exported_count += 1
                break  # Apply first matching rule only

    print(f"Export complete. Processed {exported_count} documents.")
    return exported_count

if __name__ == '__main__':
    process_documents()

