interface ReaderDocument {
  id: string;
  title: string;
  sourceUrl: string;
  numHighlights: number;
  tags: string[];
  savedAt: Date;
}

interface AutomationRule {
  id: string;
  name: string;
  trigger: 'new_highlight' | 'new_document' | 'tag_applied';
  conditions: Condition[];
  actions: Action[];
  enabled: boolean;
}

interface Condition {
  field: string;
  operator: 'equals' | 'contains' | 'regex' | 'gt' | 'lt';
  value: string | number;
}

interface Action {
  type: 'apply_tag' | 'forward_email' | 'webhook' | 'export';
  config: Record<string, any>;
}

class ReaderAutomationService {
  private apiToken: string;
  private rules: AutomationRule[] = [];
  private webhookSecret: string;

  constructor(apiToken: string, webhookSecret: string) {
    this.apiToken = apiToken;
    this.webhookSecret = webhookSecret;
  }

  async getRecentDocuments(since: Date): Promise<ReaderDocument[]> {
    const response = await fetch(
      `https://readwise.io/api/v2/documents/?updated_after=${since.toISOString()}`,
      { headers: { 'Authorization': `Token ${this.apiToken}` } }
    );
    const data = await response.json();
    return data.results.map((doc: any) => ({
      id: doc.id,
      title: doc.title,
      sourceUrl: doc.source_url,
      numHighlights: doc.num_highlights,
      tags: doc.tags || [],
      savedAt: new Date(doc.saved_at)
    }));
  }

  async applyTags(documentId: string, tags: string[]): Promise<void> {
    await fetch(`https://readwise.io/api/v2/documents/${documentId}/`, {
      method: 'PATCH',
      headers: {
        'Authorization': `Token ${this.apiToken}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ tags })
    });
  }

  private evaluateCondition(doc: ReaderDocument, condition: Condition): boolean {
    const fieldValue = this.getNestedValue(doc, condition.field);

    switch (condition.operator) {
      case 'equals':
        return fieldValue === condition.value;
      case 'contains':
        return String(fieldValue).includes(String(condition.value));
      case 'regex':
        return new RegExp(String(condition.value)).test(String(fieldValue));
      case 'gt':
        return Number(fieldValue) > Number(condition.value);
      case 'lt':
        return Number(fieldValue) < Number(condition.value));
      default:
        return false;
    }
  }

  private getNestedValue(obj: any, path: string): any {
    return path.split('.').reduce((current, key) => current?.[key], obj);
  }

  private async executeAction(doc: ReaderDocument, action: Action): Promise<void> {
    switch (action.type) {
      case 'apply_tag':
        const newTags = [...new Set([...doc.tags, ...action.config.tags])];
        await this.applyTags(doc.id, newTags);
        break;
      case 'forward_email':
        await this.sendEmail(doc, action.config);
        break;
      case 'webhook':
        await this.callWebhook(doc, action.config);
        break;
      case 'export':
        await this.exportDocument(doc, action.config);
        break;
    }
  }

  async processDocument(doc: ReaderDocument): Promise<string[]> {
    const appliedRules: string[] = [];

    for (const rule of this.rules.filter(r => r.enabled)) {
      const conditionsMet = rule.conditions.every(c => 
        this.evaluateCondition(doc, c)
      );

      if (conditionsMet) {
        console.log(`Rule "${rule.name}" matched for document: ${doc.title}`);
        for (const action of rule.actions) {
          await this.executeAction(doc, action);
        }
        appliedRules.push(rule.id);
      }
    }

    return appliedRules;
  }

  async runScheduledProcessing(): Promise<void> {
    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
    const documents = await this.getRecentDocuments(oneHourAgo);

    console.log(`Processing ${documents.length} documents...`);

    for (const doc of documents) {
      const applied = await this.processDocument(doc);
      if (applied.length > 0) {
        console.log(`Applied ${applied.length} rules to: ${doc.title}`);
      }
    }
  }

  addRule(rule: AutomationRule): void {
    this.rules.push(rule);
    console.log(`Added rule: ${rule.name}`);
  }
}

// Example usage
const automation = new ReaderAutomationService(
  process.env.READWISE_TOKEN!,
  process.env.WEBHOOK_SECRET!
);

automation.addRule({
  id: 'auto-tag-technical',
  name: 'Auto-tag technical content',
  trigger: 'new_document',
  conditions: [
    { field: 'sourceUrl', operator: 'contains', value: 'github.com' }
  ],
  actions: [
    { type: 'apply_tag', config: { tags: ['code', 'technical'] } }
  ],
  enabled: true
});

// Run processing
automation.runScheduledProcessing();

